const d = msg.data || {};
const apiKey = flow.get("openai_api_key") || "";
const model  = flow.get("openai_model")  || "gpt-4o";

if (!apiKey) {
    msg.response = { action:"enhancePrompt", status:"error", message:"No OpenAI API key configured. Set OPENAI_API_KEY on the flow." };
    return [null, msg];            // output 2 → error path
}

msg.url = "https://api.openai.com/v1/chat/completions";
msg.headers = {
    "Content-Type":  "application/json",
    "Authorization": "Bearer " + apiKey
};
msg.payload = {
    model: model,
    temperature: 0.3,
    max_tokens: 4096,
    messages: [
        {
            role: "system",
            content: "You are an expert at writing LLM transformation prompts for schema-to-schema data conversion. Given a user's rough prompt, improve it to be clearer, more specific, and more effective. Keep the user's original intent. Return ONLY the improved prompt text, nothing else."
        },
        {
            role: "user",
            content: "Source schema: " + (d.sourceSchema || "") +
                     "\nTarget schema: " + (d.targetSchema || "") +
                     "\n\nSchema context:\n" + (d.schemaContext || "(none)") +
                     "\n\nUser's raw prompt:\n" + (d.rawPrompt || "") +
                     "\n\nReturn the improved prompt only."
        }
    ]
};

return [msg, null];               // output 1 → http request

const body = msg.payload || {};
const content = (body.choices && body.choices[0] && body.choices[0].message && body.choices[0].message.content) || "";

msg.response = {
    action: "enhancePrompt",
    status: "success",
    enhancedPrompt: content.trim()
};
delete msg.payload;
delete msg.headers;
delete msg.url;
return msg;

const status = msg.statusCode || 0;
const body   = msg.payload || {};
const errMsg = (body.error && body.error.message) || JSON.stringify(body);

msg.response = {
    action: "enhancePrompt",
    status: "error",
    message: "OpenAI returned HTTP " + status + ": " + errMsg
};
delete msg.payload;
delete msg.headers;
delete msg.url;
return msg;

const d = msg.data || {};

// generate unique id
const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
let rnd = '';
for (let i = 0; i < 8; i++) rnd += chars[Math.floor(Math.random() * chars.length)];
const id  = 'prompt-' + Date.now().toString(36) + rnd;
const now = new Date().toISOString().slice(0, 10);

const prompt = {
    id:                   id,
    version:              d.version || "1.0",
    status:               "writing code",
    sourceSchema:         d.sourceSchema || "",
    targetSchema:         d.targetSchema || "",
    template:             d.template || "",
    examples:             d.examples || "",
    constraints:          d.constraints || "",
    originalPrompt:       d.template || "",
    enhancedPrompt:       d.enhancedPrompt || "",
    generatedCode:        "",
    codeGenerationStatus: "generating",
    createdAt:            now,
    updatedAt:            now,
    lastGeneratedAt:      ""
};

msg._promptData = prompt;
msg.collection  = "sr_prompts";
msg.operation   = "insertOne";
msg.payload     = prompt;
return msg;

// This goes straight to the UI so the user sees the prompt appear immediately.
msg.response = {
    action: "createPrompt",
    status: "success",
    prompt: msg._promptData
};
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const p      = msg._promptData || {};
const apiKey = flow.get("openai_api_key") || "";
const model  = flow.get("openai_model")  || "gpt-4o";

if (!apiKey) {
    // No API key → cannot generate code. Mark as error.
    msg._codeGenError = "No OpenAI API key configured.";
    msg._generatedCode = "";
    return [null, msg];   // output 2 → skip to update-with-error
}

msg.url = "https://api.openai.com/v1/chat/completions";
msg.headers = {
    "Content-Type":  "application/json",
    "Authorization": "Bearer " + apiKey
};
msg.payload = {
    model: model,
    temperature: 0.3,
    max_tokens: 4096,
    messages: [
        {
            role: "system",
            content: "You are a code generator. Output ONLY a single JavaScript function named `transform` that takes one argument `input` (a plain object) and returns the transformed object. No markdown fences, no explanation, no imports. The function must be deterministic, handle missing fields gracefully, and produce valid JSON-serialisable output."
        },
        {
            role: "user",
            content: "Source schema: " + (p.sourceSchema || "") +
                     "\nTarget schema: " + (p.targetSchema || "") +
                     "\n\nPrompt / mapping instructions:\n" + (p.template || "") +
                     "\n\nGenerate the JavaScript transform function now."
        }
    ]
};

return [msg, null];      // output 1 → http request

const body = msg.payload || {};
let code = (body.choices && body.choices[0] && body.choices[0].message && body.choices[0].message.content) || "";

// Strip markdown fences if present
code = code.replace(/^```(?:javascript|js)?\s*\n?/i, "")
           .replace(/\n?```\s*$/i, "")
           .trim();

msg._generatedCode = code;
msg._codeGenError  = null;
return msg;

const status = msg.statusCode || 0;
const body   = msg.payload || {};
const errMsg = (body.error && body.error.message) || JSON.stringify(body);

msg._generatedCode = "";
msg._codeGenError  = "OpenAI HTTP " + status + ": " + errMsg;
return msg;

const p   = msg._promptData || {};
const now = new Date().toISOString().slice(0, 10);
const hasCode = !!msg._generatedCode;

msg.collection = "sr_prompts";
msg.operation  = "updateOne";
msg.payload = [
    { id: p.id },
    { $set: {
        generatedCode:        msg._generatedCode || "",
        codeGenerationStatus: hasCode ? "completed" : "error",
        status:               hasCode ? "active"    : "error",
        lastGeneratedAt:      hasCode ? now : "",
        updatedAt:            now
    }}
];
return msg;

const p       = msg._promptData || {};
const now     = new Date().toISOString().slice(0, 10);
const hasCode = !!msg._generatedCode;

msg.response = {
    action:         "codeGenerated",
    status:         hasCode ? "success" : "error",
    promptId:       p.id,
    generatedCode:  msg._generatedCode || "",
    lastGeneratedAt: hasCode ? now : "",
    updatedAt:      now,
    message:        msg._codeGenError || ""
};

delete msg._promptData;
delete msg._generatedCode;
delete msg._codeGenError;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

msg.collection = "sr_prompts";
msg.operation  = "find";
msg.payload    = [{}, { projection: { _id: 0 } }];
return msg;

msg.response = {
    action:  "listPrompts",
    status:  "success",
    prompts: Array.isArray(msg.payload) ? msg.payload : []
};
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d   = msg.data || {};
const now = new Date().toISOString().slice(0, 10);
msg._promptId  = d.promptId;
msg._savedCode = d.code || "";
msg.collection = "sr_prompts";
msg.operation  = "updateOne";
msg.payload    = [
    { id: d.promptId },
    { $set: { generatedCode: d.code || "", updatedAt: now } }
