    config:   config
};
delete msg._configId;
delete msg._isNew;
delete msg._configData;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d = msg.data || {};
msg._configId  = d.configId;
msg.collection = "sr_llm_configs";
msg.operation  = "deleteOne";
msg.payload    = { id: d.configId };
return msg;

msg.response = {
    action:   "deleteLlmConfig",
    status:   "success",
    configId: msg._configId
};
delete msg._configId;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d   = msg.data || {};
const now = new Date().toISOString().slice(0, 10);
const models = Array.isArray(d.models) ? d.models : [];

if (d.id) {
    msg._providerId   = d.id;
    msg._isNew        = false;
    msg._providerData = d;
    msg.collection    = "sr_providers";
    msg.operation     = "updateOne";
    msg.payload = [
        { id: d.id },
        { $set: {
            name:        d.name || "",
            type:        d.type || "openai",
            apiEndpoint: d.apiEndpoint || "",
            models:      models,
            isDefault:   !!d.isDefault,
            precedence:  d.precedence || 1,
            status:      d.status || "active",
            updatedAt:   now
        }}
    ];
} else {
    const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
    let rnd = '';
    for (let i = 0; i < 6; i++) rnd += chars[Math.floor(Math.random() * chars.length)];
    const id = 'prov-' + rnd;
    msg._providerId = id;
    msg._isNew      = true;
    const provider = {
        id:          id,
        name:        d.name || "",
        type:        d.type || "openai",
        apiEndpoint: d.apiEndpoint || "",
        models:      models,
        isDefault:   !!d.isDefault,
        precedence:  d.precedence || 1,
        status:      d.status || "active",
        createdAt:   now,
        updatedAt:   now
    };
    msg._providerData = provider;
    msg.collection    = "sr_providers";
    msg.operation     = "insertOne";
    msg.payload       = provider;
}

// If this provider is default, clear default from others
if (d.isDefault) {
    msg._enforceDefault = true;
}
return msg;

const d   = msg._providerData || {};
const now = new Date().toISOString().slice(0, 10);
const provider = {
    id:          msg._providerId,
    name:        d.name || "",
    type:        d.type || "openai",
    apiEndpoint: d.apiEndpoint || "",
    models:      Array.isArray(d.models) ? d.models : [],
    isDefault:   !!d.isDefault,
    precedence:  d.precedence || 1,
    status:      d.status || "active",
    createdAt:   d.createdAt || now,
    updatedAt:   now
};
msg.response = {
    action:     "saveProvider",
    status:     "success",
    providerId: msg._providerId,
    isNew:      !!msg._isNew,
    provider:   provider
};
delete msg._providerId;
delete msg._isNew;
delete msg._providerData;
delete msg._enforceDefault;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d = msg.data || {};
msg._providerId = d.providerId;
msg.collection  = "sr_providers";
msg.operation   = "deleteOne";
msg.payload     = { id: d.providerId };
return msg;

msg.response = {
    action:     "deleteProvider",
    status:     "success",
    providerId: msg._providerId
};
delete msg._providerId;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d = msg.data || {};
msg._reorderProviderId = d.providerId;
msg._reorderDirection  = d.direction || "up";
msg.collection = "sr_providers";
msg.operation  = "find";
msg.payload    = [{}, { projection: { _id: 0 }, sort: { precedence: 1 } }];
return msg;

const providers = Array.isArray(msg.payload) ? msg.payload : [];
const id   = msg._reorderProviderId;
const dir  = msg._reorderDirection;
const idx  = providers.findIndex(p => p.id === id);

if (idx !== -1) {
    if (dir === "up" && idx > 0) {
        const tmp = providers[idx];
        providers[idx] = providers[idx - 1];
        providers[idx - 1] = tmp;
    } else if (dir === "down" && idx < providers.length - 1) {
        const tmp = providers[idx];
        providers[idx] = providers[idx + 1];
        providers[idx + 1] = tmp;
    }
    providers.forEach((p, i) => { p.precedence = i + 1; });
}

msg.response = {
    action:    "reorderProvider",
    status:    "success",
    providers: providers
};
delete msg._reorderProviderId;
delete msg._reorderDirection;
delete msg.payload;
delete msg.collection;
delete msg.operation;
return msg;

const d = msg.data || {};
const total = d.scope === "all" ? 275 : d.scope === "catalogue" ? 120 : 50;
const startedAt = new Date().toISOString().replace("T", " ").slice(0, 16);

// Send immediate "started" response
var startMsg = RED.util.cloneMessage(msg);
startMsg.response = {
    action: "startBatchRetransform",
    status: "success",
    totalAssets: total,
    startedAt: startedAt
};
delete startMsg.payload;
node.send(startMsg);

// Store batch state in flow context
var state = { status: "running", total: total, processed: 0, startedAt: startedAt };
flow.set("batchState", state);

var processed = 0;
var errorCount = 0;
var errors = [];

var intervalId = setInterval(function() {
    var bs = flow.get("batchState") || {};
    if (bs.status !== "running") {
        clearInterval(intervalId);
        flow.set("batchIntervalId", null);
        return;
    }
    var step = Math.ceil(total / 20);
    processed = Math.min(total, processed + step);
    var progress = Math.round((processed / total) * 100);

    if (processed > total * 0.6 && errorCount === 0) {
        errorCount = Math.ceil(total * 0.02);
        errors = [
            { assetId: "asset-err-001", message: "SHACL validation failed", timestamp: new Date().toISOString().slice(0, 19) },
            { assetId: "asset-err-002", message: "LLM timeout exceeded", timestamp: new Date().toISOString().slice(0, 19) }
        ];
    }

    var update = {
        action: "batchRetransformProgress",
        status: processed >= total ? "completed" : "running",
        progress: progress,
        processedAssets: processed,
        totalAssets: total,
        successCount: processed - errorCount,
        errorCount: errorCount,
        skippedCount: 0,
        errors: errors,
        startedAt: startedAt,
        completedAt: processed >= total ? new Date().toISOString().replace("T", " ").slice(0, 16) : ""
    };

    if (processed >= total) {
        clearInterval(intervalId);
        flow.set("batchIntervalId", null);
        flow.set("batchState", { status: "completed" });
        var triggerLabels = { prompt_change: "Prompt changed", strategy_change: "Strategy changed", llm_change: "LLM config changed", manual: "Manual trigger" };
        var scopeLabels = { all: "All assets", catalogue: "Catalogue: " + (d.catalogueFilter || "—"), query: "Query: " + (d.queryFilter || "—") };
        update.historyEntry = {
            id: "br-" + String(Date.now()).slice(-6),
            trigger: triggerLabels[d.trigger] || d.trigger,
            scope: scopeLabels[d.scope] || d.scope,
            dryRun: !!d.dryRun,
            total: total,
            success: processed - errorCount,
            errors: errorCount,
            skipped: 0,
            startedAt: startedAt,
            completedAt: update.completedAt,
            status: "completed"
        };
    }

    var progressMsg = RED.util.cloneMessage(msg);
    progressMsg.response = update;
    delete progressMsg.payload;
    node.send(progressMsg);
}, 400);

